create table public.cash_categories (id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,name text not null,direction text not null check(direction in('in','out')),unique(organization_id,name,direction));
create table public.cash_transfers (id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,from_account_id uuid not null references public.cash_accounts(id),to_account_id uuid not null references public.cash_accounts(id),amount numeric(14,2) not null check(amount>0),transferred_at timestamptz not null default now(),notes text,created_by uuid references auth.users(id));
create table public.cash_reconciliations (id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,cash_account_id uuid not null references public.cash_accounts(id),book_balance numeric(14,2) not null,actual_balance numeric(14,2) not null,reconciled_at timestamptz not null default now(),notes text,reconciled_by uuid references auth.users(id));
alter table public.cash_categories enable row level security;alter table public.cash_transfers enable row level security;alter table public.cash_reconciliations enable row level security;
create policy "finance manages cash categories" on public.cash_categories for all using(public.can_manage_finance(organization_id)) with check(public.can_manage_finance(organization_id));
create policy "finance manages transfers" on public.cash_transfers for all using(public.can_manage_finance(organization_id)) with check(public.can_manage_finance(organization_id));
create policy "finance manages reconciliations" on public.cash_reconciliations for all using(public.can_manage_finance(organization_id)) with check(public.can_manage_finance(organization_id));
